import{c as l,Q as e,j as i,m as t}from"./chunks/framework.Bhbi9jCp.js";const u=JSON.parse('{"title":"直播系统:RTMP / SRT / WebRTC / HLS","description":"","frontmatter":{},"headers":[],"relativePath":"mediaTechLearning/26-直播系统-RTMP-SRT-WebRTC-HLS.md","filePath":"mediaTechLearning/26-直播系统-RTMP-SRT-WebRTC-HLS.md","lastUpdated":1780887690000}'),s={name:"mediaTechLearning/26-直播系统-RTMP-SRT-WebRTC-HLS.md"};function n(r,a,p,o,h,c){return e(),i("div",null,[...a[0]||(a[0]=[t(`<h1 id="直播系统-rtmp-srt-webrtc-hls" tabindex="-1">直播系统:RTMP / SRT / WebRTC / HLS <a class="header-anchor" href="#直播系统-rtmp-srt-webrtc-hls" aria-label="Permalink to &quot;直播系统:RTMP / SRT / WebRTC / HLS&quot;">​</a></h1><p>直播不是视频会议放大版。直播的主目标是规模、稳定和成本,低延迟只是其中一个取舍项。</p><blockquote><p>一句话先记住:<strong>直播链路 = 推流 -&gt; 转码/转封装 -&gt; 分发 -&gt; 播放</strong>。RTMP/SRT/WebRTC 常在上行,HLS/FLV/WebRTC 常在下行。</p></blockquote><hr><h2 id="一、标准直播链路" tabindex="-1">一、标准直播链路 <a class="header-anchor" href="#一、标准直播链路" aria-label="Permalink to &quot;一、标准直播链路&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>主播端 OBS / App</span></span>
<span class="line"><span>  -&gt; 推流网关</span></span>
<span class="line"><span>  -&gt; 转码 / 截帧 / 审核</span></span>
<span class="line"><span>  -&gt; CDN 分发</span></span>
<span class="line"><span>  -&gt; 播放器</span></span></code></pre></div><p>大直播系统还会加:</p><ul><li>鉴权</li><li>断流重连</li><li>多码率转码</li><li>录制回放</li><li>实时截图审核</li><li>质量监控</li></ul><hr><h2 id="二、rtmp" tabindex="-1">二、RTMP <a class="header-anchor" href="#二、rtmp" aria-label="Permalink to &quot;二、RTMP&quot;">​</a></h2><p>RTMP 是直播上行老标准:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>OBS -&gt; rtmp://server/live/streamKey</span></span></code></pre></div><p>优点:</p><ul><li>推流工具支持广</li><li>生态成熟</li><li>延迟可控</li></ul><p>缺点:</p><ul><li>浏览器原生不播 RTMP</li><li>现代低延迟和弱网能力不如新协议</li></ul><p>现在常见做法是 RTMP 推流,服务端转 HLS / FLV / WebRTC 给观众。</p><hr><h2 id="三、srt" tabindex="-1">三、SRT <a class="header-anchor" href="#三、srt" aria-label="Permalink to &quot;三、SRT&quot;">​</a></h2><p>SRT 面向不稳定公网传输,比 RTMP 更重视抗丢包和远距离传输。</p><p>适合:</p><ul><li>远程制作</li><li>跨地域上行</li><li>专业直播源回传</li></ul><p>不适合:</p><ul><li>普通浏览器直接播放</li></ul><hr><h2 id="四、webrtc-直播" tabindex="-1">四、WebRTC 直播 <a class="header-anchor" href="#四、webrtc-直播" aria-label="Permalink to &quot;四、WebRTC 直播&quot;">​</a></h2><p>WebRTC 下行可做到亚秒级延迟。适合:</p><ul><li>连麦</li><li>拍卖</li><li>在线课堂互动</li><li>低延迟赛事互动</li></ul><p>代价:</p><ul><li>CDN 生态不如 HLS 成熟</li><li>SFU/边缘节点成本高</li><li>大规模分发复杂</li></ul><p>不要为了&quot;低延迟&quot;把所有直播都改 WebRTC。先问业务是否真的需要。</p><hr><h2 id="五、hls-直播" tabindex="-1">五、HLS 直播 <a class="header-anchor" href="#五、hls-直播" aria-label="Permalink to &quot;五、HLS 直播&quot;">​</a></h2><p>HLS 普通直播延迟通常几秒到十几秒,但:</p><ul><li>CDN 友好</li><li>兼容性好</li><li>成本可控</li><li>大规模分发稳</li></ul><p>秀场、课程、带货很多场景几秒延迟可接受。稳定比极低延迟更值钱。</p><hr><h2 id="六、踩坑提醒" tabindex="-1">六、踩坑提醒 <a class="header-anchor" href="#六、踩坑提醒" aria-label="Permalink to &quot;六、踩坑提醒&quot;">​</a></h2><ol><li><strong>用会议架构做万人直播</strong>——成本和带宽会炸。</li><li><strong>所有场景追亚秒延迟</strong>——业务未必需要。</li><li><strong>只做单码率直播</strong>——弱网用户体验差。</li><li><strong>不录制</strong>——直播结束没有回放资产。</li><li><strong>推流鉴权弱</strong>——别人能推垃圾流进你的房间。</li></ol><p>下一篇:<code>27-低延迟直播.md</code>。</p>`,40)])])}const T=l(s,[["render",n]]);export{u as __pageData,T as default};
